import { HttpErrorResponse } from '@angular/common/http';
import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { Subject } from 'rxjs';
import { permissionsLabels } from 'src/app/shared/models/fmosNewRolePermissions';
import { ApiService } from 'src/app/shared/services/api.service';
import { RoleService } from 'src/app/shared/services/role.service';
import { ToastService } from 'src/app/shared/services/toast.service';
import Swal from 'sweetalert2';

@Component({
  selector: 'npr-excel-mapping',
  templateUrl: './excel-mapping.component.html',
  styleUrls: ['./excel-mapping.component.scss'],
})
export class ExcelMappingComponent implements OnInit {
  excelData: any;
  dtOptions: DataTables.Settings = {};
  dtTrigger: Subject<any> = new Subject<any>();
  isLoading: boolean = false;
  roleCodes = new permissionsLabels();
  statusArr: String[] = ['Authorized', 'Unauthorized', 'Open', 'Close'];
  excelMappingSummary: any;
  extName: any;
  currentUser: string;
  extCodeValue: any;
  extNameValue: any;
  proCodeValue: any;
  currencyValue: any;
  authStatus: any;
  recordStatus: any;
  modifiedBy: any;
  modifiedTime: any;
  authorizedBy: any;
  authorizedTime: any;
  version: any;
  mappingResponse: Object;
  sheetNo: any;
  firstTimeAuth: any;
  

  constructor(
    private apiService: ApiService,
    private roleService: RoleService,
    private toastService: ToastService,
    private router: Router
  ) {}

  ngOnInit(): void {
    this.dtOptions = {
      pagingType: 'full_numbers',
      pageLength: 5,
      columnDefs: [{ type: 'date', targets: [4] }],
      order: [[4, 'desc']],
      processing: true,
      lengthMenu: [
        [5, 10, 20, -1],
        [5, 10, 20, 30],
      ],
    };
    this.currentUser = localStorage.getItem("userFromLogin");
    this.getexcelMappingSummary();
    this.roleService.fetchScreenPermissions('Template Mapping');
    this.roleService.screenLabelList.subscribe(
      (message) => (this.roleCodes = message)
    );
    console.log(this.roleCodes);
  }
  auditLog() {
    if (this.excelMappingSummary.authStatus =='U' || this.excelMappingSummary.authStatus =='Unauthorized') {
      this.excelMappingSummary.authStatus = 'UNAUTHORIZED'
    }
    if (this.excelMappingSummary.authStatus == 'A' || this.excelMappingSummary.authStatus =='Authorized' ) {
      this.excelMappingSummary.authStatus = 'AUTHORIZED'
    }
    if (this.excelMappingSummary.recordStatus == 'O') {
      this.excelMappingSummary.recordStatus = 'OPEN'
    }
    if (this.excelMappingSummary.recordStatus == 'C') {
      this.excelMappingSummary.recordStatus = 'CLOSED'
    }
    if (this.excelMappingSummary.verifiedOnce == 'N') {
      console.log("NO");
      this.excelMappingSummary.verifiedOnce = 'NO'
    }
    if (this.excelMappingSummary.verifiedOnce == 'Y') {
      this.excelMappingSummary.verifiedOnce = 'YES'
    }
  }
  getexcelMappingSummary() {
    this.isLoading = true;
    this.apiService.getMappingSummary().subscribe((data) => {
      this.mappingResponse = data;
      for (let item of data.result) {
        item.authStatus = this.statusArr.find((i) =>
          i.startsWith(item.authStatus)
        );
      }
      console.log(this.excelData);
      this.excelData = data.result;
      this.isLoading = false;

      this.dtTrigger.next();
    });
  }
  close(exdata){

   console.log(exdata);
   this.extCodeValue =  exdata.extSysCode;
   this.extNameValue =  exdata.extSys;
   this.proCodeValue =  exdata.processName;
   this.currencyValue = exdata.currency;
 
  Swal.fire(
      {
        //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
        text: 'You are trying to Close the record. ' + ' Do you want to proceed?',
        showCancelButton: true,
        confirmButtonColor: '#3085d6',
        cancelButtonColor: '#d33',
        // confirmButtonText: 'PROCEED.'
        cancelButtonText: 'NO',
        confirmButtonText: 'YES', 'icon': 'info'
      }
    ).then((result => {
      if(result.isConfirmed=== true){
        this.apiService.getExcelMappingDataforEdit(this.extCodeValue,this.proCodeValue,this.extNameValue).subscribe((editResp) =>{
          console.log("This. is new Resp",editResp);
          
          this.currencyValue=editResp.currency[0];
          this.sheetNo=editResp.currencySheetMap[this.currencyValue]; 
          this.apiService.getAllMappingByExtSysAndProcessCode(this.extCodeValue,this.proCodeValue, this.currencyValue, this.sheetNo)
          .subscribe(mappingResponse => {
            console.log(mappingResponse);
    
            if(mappingResponse){
              if(this.currencyValue){
            
                this.apiService.onClcikOFCloseOfUpdateExcelMApping({subArray: mappingResponse},this.extCodeValue,this.proCodeValue,this.extNameValue,this.currencyValue).subscribe(closeResp => {
                  console.log(closeResp);
                  this.mappingResponse = closeResp;
                  if (this.mappingResponse) {
                    this.authStatus = this.mappingResponse[0]?.authStatus;
                    this.recordStatus = this.mappingResponse[0]?.recordStatus;
                    this.modifiedBy = this.mappingResponse[0]?.modifiedBy;
                    this.modifiedTime = this.mappingResponse[0]?.modifiedTime;
                    this.authorizedBy = this.mappingResponse[0]?.authorizedBy;
                    this.authorizedTime = this.mappingResponse[0]?.authorizedTime;
                    this.version = this.mappingResponse[0]?.version;
                    
                    if (this.authStatus === 'U') {
                      this.authStatus = 'UNAUTHORIZED';
                    }
                    if (this.authStatus === 'A') {
                      this.authStatus = 'AUTHORIZED';
                    }
                    if (this.recordStatus === 'C') {
                      this.recordStatus = 'CLOSED';
                    }
                    if (this.recordStatus === 'O') {
                      this.recordStatus = 'OPEN';
                    }
                    Swal.fire({
                      title: 'Record is Closed',
                      icon: 'success'
                    }).then(() => window.location.reload());
                    this.auditLog();
                  }
                  else {
                    Swal.fire({
                      title: 'Failed to Close the Recored!',
                      icon: 'error'
                    });
                  }
                },
                  error => {
                    if (HttpErrorResponse) {
                      Swal.fire({
                        text: 'Server Error!',
                        icon: 'error'
                      });
                    }
                  });
                }
            }
          })
        
         })

    }}));
     
     
          
      
  }
 
  open(exdata){
    console.log(exdata);
    this.extCodeValue =  exdata.extSysCode;
   this.extNameValue =  exdata.extSys;
   this.proCodeValue =  exdata.processName;
   this.currencyValue = exdata.currency;
     
     Swal.fire(
      {
        //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
        text: 'You are trying to re-open record. ' + ' Do you want to proceed?',
        showCancelButton: true,
        confirmButtonColor: '#3085d6',
        cancelButtonColor: '#d33',
        // confirmButtonText: 'PROCEED.'
        cancelButtonText: 'NO',
        confirmButtonText: 'YES', 'icon': 'info'
      }
    ).then((result => {
      console.log("this is reopen ", result);
      if (result.isConfirmed === true) {
        this.apiService.getExcelMappingDataforEdit(this.extCodeValue,this.proCodeValue,this.extNameValue).subscribe((editResp) =>{
          console.log("This. is new Resp",editResp);
          this.currencyValue=editResp.currency[0];
          this.sheetNo=editResp.currencySheetMap[this.currencyValue]; 
          this.apiService.getAllMappingByExtSysAndProcessCode(this.extCodeValue,this.proCodeValue, this.currencyValue, this.sheetNo)
          .subscribe(mappingResponse => {

    this.apiService.onClcikOfReopenOfUpdateExcelMapping({subArray: mappingResponse},this.extCodeValue,this.proCodeValue,this.extNameValue,this.currencyValue).subscribe(openResp => {
      console.log(openResp);
      this.mappingResponse = openResp;
      if (this.mappingResponse) {
        this.authStatus = this.mappingResponse[0]?.authStatus;
        this.recordStatus = this.mappingResponse[0]?.recordStatus;
        this.modifiedBy = this.mappingResponse[0]?.modifiedBy;
        this.modifiedTime = this.mappingResponse[0]?.modifiedTime;
        this.authorizedBy = this.mappingResponse[0]?.authorizedBy;
        this.authorizedTime = this.mappingResponse[0]?.authorizedTime;
        this.version = this.mappingResponse[0]?.version;
        
        if (this.authStatus === 'U') {
          this.authStatus = 'UNAUTHORIZED';
        }
        if (this.authStatus === 'A') {
          this.authStatus = 'AUTHORIZED';
        }
        if (this.recordStatus === 'C') {
          this.recordStatus = 'CLOSED';
        }
        if (this.recordStatus === 'O') {
          this.recordStatus = 'OPEN';
        }
        Swal.fire({
          title: 'Record is Reopened',
          icon: 'success'
        }).then(() => window.location.reload());
        this.auditLog();
      }
      else {
        Swal.fire({
          title: 'Failed to Reopen the Record!',
          icon: 'error'
        });
      }
    },
      error => {
        if (HttpErrorResponse) {
          Swal.fire({
            text: 'Server Error!',
            icon: 'error'
          });
        }
      });
    });
    });
    }}));

  }
 delete(exdata){
  console.log(exdata);


  }
  auth(exdata){
    console.log(exdata);
    this.currentUser = localStorage.getItem("userFromLogin");
    console.log("this.currentUser",this.currentUser,);
    this.extCodeValue =  exdata.extSysCode;
   this.extNameValue =  exdata.extSys;
   this.proCodeValue =  exdata.processName;
   this.currencyValue = exdata.currency;
    if (this.modifiedBy === this.currentUser) {
      Swal.fire({
        title: 'Maker Cannot Authorized the Record!',
        icon: 'error'
      });
    } else {
      Swal.fire(
        {
          text: 'You are trying to Authorize the record. ' + ' Do you want to proceed?',
          showCancelButton: true,
          confirmButtonColor: '#E6224A',
          cancelButtonColor: '#011945',
          // confirmButtonText: 'PROCEED.'
          cancelButtonText: 'NO',
          confirmButtonText: 'YES',
          icon:'info'
        }
      ).then((result => {
        if(result.isConfirmed=== true){
          this.apiService.getExcelMappingDataforEdit(this.extCodeValue,this.proCodeValue,this.extNameValue).subscribe((editResp) =>{
            console.log("This. is new Resp",editResp);
            this.currencyValue=editResp.currency[0];
            this.sheetNo=editResp.currencySheetMap[this.currencyValue]; 
            this.apiService.getAllMappingByExtSysAndProcessCode(this.extCodeValue,this.proCodeValue, this.currencyValue, this.sheetNo)
            .subscribe(mappingResponse => {
              if(mappingResponse){
                if(this.currencyValue){
           this.apiService.onAuthorizingTheRecordOfExcelMApping({subArray: mappingResponse},this.extNameValue,this.proCodeValue,this.extCodeValue, this.currentUser,this.currencyValue)
             .subscribe(authResp => {
             this.mappingResponse = authResp;
           if(this.mappingResponse){
              this.authStatus = this.mappingResponse[0]?.authStatus;
               this.recordStatus = this.mappingResponse[0]?.recordStatus;
               this.modifiedBy = this.mappingResponse[0]?.modifiedBy;
               this.modifiedTime = this.mappingResponse[0]?.inputDtStamp;
               this.authorizedBy = this.mappingResponse[0]?.authorizedBy;
               this.authorizedTime = this.mappingResponse[0]?.authorizedDtStamp;
               this.version = this.mappingResponse[0]?.version;
               this.firstTimeAuth=this.mappingResponse[0]?.firstTimeAuth;
               this.modifiedBy = this.mappingResponse[0]?.inputBy;
          
          if (this.authStatus === 'U') {
            this.authStatus = 'UNAUTHORIZED';
          }
          if (this.authStatus === 'A') {
            this.authStatus = 'AUTHORIZED';
          }
          if (this.recordStatus === 'C') {
            this.recordStatus = 'CLOSED';
          }
          if (this.recordStatus === 'O') {
            this.recordStatus = 'OPEN';
          }
          if (this.firstTimeAuth === 'Y') {
            this.firstTimeAuth = 'YES';
          }
          if (this.firstTimeAuth === 'N') {
            this.firstTimeAuth = 'NO';
          }
          Swal.fire({
            title: 'Record is Authorized',
            icon: 'success'
          }).then(() => window.location.reload());

           }
        })
         }
      }     
      })
      })
    }}));
    }

  }

  setDataFromSummaryToUpdateExcelMapping(element) {
    
    localStorage.setItem('summryResponse', JSON.stringify(element));
    this.apiService.setexcelSummaryData({
      extSysCode: element.extSysCode,
      extSys: element.extSys,
      processName: element.processName,
      authStatus: element.authStatus,
    });
    
    this.router.navigate(['/excel-mapping/excel-mapping-edit']);
  }
}
